     }

-    /// Emit inline block end: })
-    /// Writes directly to codegen output
+    /// DEPRECATED: Use emitInlineBlock with callback instead
     pub fn emitInlineBlockEnd(self: *NativeCodegen) CodegenError!void {
         try self.emit("})");
     }

